// ========================================
// Tổng hợp health report
// ========================================

// Lấy kết quả OpenAI check
const openaiResult = $input.first().json;
const openaiOk = !!(openaiResult.data || openaiResult.object);

// Lấy kết quả Postgres stats
const pgResults = $('PG: Get Stats').all().map(item => item.json);

const stats = {};
pgResults.forEach(row => {
  if (row.check_name) {
    stats[row.check_name] = parseInt(row.result) || 0;
  }
});

// Build health report
const health = {
  timestamp: new Date().toISOString(),
  overall: 'healthy',
  services: {
    supabase: {
      status: pgResults.length > 0 ? 'healthy' : 'error',
      message: pgResults.length > 0 ? 'Kết nối thành công' : 'Không kết nối được'
    },
    openai: {
      status: openaiOk ? 'healthy' : 'error',
      message: openaiOk ? 'API hoạt động' : 'Không kết nối được OpenAI'
    },
    n8n: {
      status: 'healthy',
      message: 'Workflow đang chạy'
    }
  },
  stats: {
    total_documents: stats.total_documents || 0,
    sop_count: stats.sop_count || 0,
    guideline_count: stats.guideline_count || 0,
    form_count: stats.form_count || 0,
    docs_vi: stats.docs_vi || 0,
    docs_en: stats.docs_en || 0,
    docs_bilingual: stats.docs_bilingual || 0,
    docs_draft: stats.docs_draft || 0,
    docs_indexed: stats.docs_indexed || 0,
    docs_pending_review: stats.docs_pending_review || 0,
    docs_approved: stats.docs_approved || 0,
    ai_translations_pending: stats.ai_translations_pending || 0,
    total_chunks: stats.total_chunks || 0,
    total_ai_queries: stats.total_ai_queries || 0,
    pending_jobs: stats.pending_jobs || 0,
    failed_jobs: stats.failed_jobs || 0,
    total_users: stats.total_users || 0,
    unresolved_security_events: stats.security_events || 0
  },
  warnings: []
};

// Detect warnings
if (stats.failed_jobs > 0) health.warnings.push('Có ' + stats.failed_jobs + ' ingest job bị lỗi');
if (stats.docs_pending_review > 5) health.warnings.push('Có ' + stats.docs_pending_review + ' tài liệu chờ review');
if (stats.ai_translations_pending > 0) health.warnings.push('Có ' + stats.ai_translations_pending + ' bản dịch AI chưa duyệt');
if (stats.security_events > 0) {
  health.warnings.push('Có ' + stats.security_events + ' sự kiện bảo mật chưa xử lý');
  health.overall = 'warning';
}
if (!openaiOk) health.overall = 'degraded';
if (pgResults.length === 0) health.overall = 'error';

return [{ json: health }];
